css:
* { margin: 0; padding: 0; box-sizing: border-box; }

body {
  font-family: Arial, sans-serif;
  font-size: 11px;
  color: #1a1a1a;
  padding: 14px;
  background: #fff;
}

.bold{
    font-weight:bold !important;
}

/* CONTAINER */
.container {
  width: 100%;
  max-width: 100%;
}

/* HEADER */
.header {
  text-align: center;
  margin-bottom: 15px;
}
.header h2 {
  font-size: 16px;
  font-weight: bold;
}
.header p {
  font-size: 10px;
  color: #666;
}

/* ROW / COL (Bootstrap-like) */
.row {
  display: flex;
  gap: 12px;
  margin-bottom: 12px;
}

.col {
  flex: 1;
}

/* CARD */
.card {
  border: 1px solid #dcdcdc;
  border-radius: 6px;
  overflow: hidden;
}

/* CARD HEADER (LIGHT GREEN) */
.card-header {
  background: #e6f4ea;
  border-bottom: 1px solid #cce3d3;
  padding: 6px 8px;
  font-size: 10px;
  font-weight: bold;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

/* CARD BODY */
.card-body {
  padding: 8px;
}

/* TABLE */
table {
  width: 100%;
  border-collapse: collapse;
}

td {
  padding: 5px 4px;
  vertical-align: middle;
}

/* ROW DIVIDERS */
tr {
  border-bottom: 1px solid #eee;
}
tr:last-child {
  border-bottom: none;
}

/* LABEL */
td.label {
  color: #333;
}

/* SIGN */
td.sign {
  width: 18px;
  text-align: center;
  color: #888;
}

/* AMOUNT */
td.amount {
  text-align: right;
  font-family: monospace;
  white-space: nowrap;
}

/* STATES */
.pos { color: #1a7a3c; }
.neg { color: #c0392b; }

/* TOTAL */
.total td {
  border-top: 2px solid #000;
  border-bottom: 2px solid #000;
  font-weight: bold;
  font-size: 12px;
}

/* SUBTOTAL */
.subtotal td {
  border-top: 1px solid #aaa;
  font-weight: bold;
}

/* DIFF */
.diff td {
  font-weight: bold;
  font-size: 12px;
}

.print-format td, .print-format th {
    vertical-align: top !important;
    padding: 3px !important;
}
.footer {
  text-align: center;
  font-size: 9px;
  color: #888;
  margin-top: 15px;
}

html:
{% set cashier_name = frappe.db.get_value("User", doc.user, "full_name") %}
{% set opening = frappe.get_doc("POS Opening Shift", doc.pos_opening_shift) %}

{% macro fmt(val) %}{{ frappe.format_value(val, {"fieldtype": "Currency"}) }}{% endmacro %}
{% set change_mop = frappe.db.get_value("POS Profile", doc.pos_profile, "posa_cash_mode_of_payment") %}

<div class="container">

{% set ns = namespace(
  opening_bal=0,
  safe_total=0,
  check_total=0,
  other_total=0,
  invoice_total=0,
  payment_total=0,
  cash_payment_total=0
) %}

<!-- OPENING -->
{% if opening and opening.balance_details %}
{% for pr in doc.payment_reconciliation %}
    {% set ns.opening_bal = ns.opening_bal + (pr.opening_amount or 0) %}
{% endfor %}
{% endif %}

<!-- JOURNAL ENTRIES -->
{% for je in doc.pos_journal_entries %}
  {% if je.custom_safe_entry %}
    {% set ns.safe_total = ns.safe_total + (je.amount or 0) %}
  {% elif je.custom_check_entry %}
    {% set ns.check_total = ns.check_total + (je.amount or 0) %}
  {% else %}
    {% set ns.other_total = ns.other_total + (je.amount or 0) %}
  {% endif %}
{% endfor %}

<!-- INVOICES (GROUPED BY SUPPLIER) -->
{% set inv_ns = namespace(suppliers={}, qtys={}) %}

{% for tx in doc.pos_transactions %}
  {% set supplier = tx.custom_supplier or "Other" %}

  {% if supplier in inv_ns.suppliers %}
    {% set inv_ns.suppliers = dict(inv_ns.suppliers, **{
      supplier: inv_ns.suppliers[supplier] + (tx.paid_amount or 0)
    }) %}
    {% set inv_ns.qtys = dict(inv_ns.qtys, **{
      supplier: inv_ns.qtys[supplier] + 1
    }) %}
  {% else %}
    {% set inv_ns.suppliers = dict(inv_ns.suppliers, **{
      supplier: (tx.paid_amount or 0)
    }) %}
    {% set inv_ns.qtys = dict(inv_ns.qtys, **{
      supplier: 1
    }) %}
  {% endif %}

  {% set ns.invoice_total = ns.invoice_total + (tx.paid_amount or 0) %}
{% endfor %}

<!-- PAYMENTS -->
{% for pay in doc.pos_payments %}
  {% set ns.payment_total = ns.payment_total + (pay.paid_amount or 0) %}
  {% if pay.mode_of_payment == change_mop %}
    {% set ns.cash_payment_total = ns.cash_payment_total + (pay.paid_amount or 0) %}
  {% endif %}
{% endfor %}

{% set expected = ns.opening_bal + ns.safe_total + ns.check_total + ns.other_total + ns.invoice_total + ns.cash_payment_total %}

{% set closing_bal = 0 %}
{% set diff_val = 0 %}

{% if doc.payment_reconciliation %}
  {% set pr = doc.payment_reconciliation[0] %}
  {% set closing_bal = pr.closing_amount or 0 %}
  {% set diff_val = closing_bal - expected %}
{% endif %}

<!-- HEADER -->
<div class="header">
  <h2>CONCILIACIÓN DE CAJA</h2>
  {%if doc.docstatus == 0 %}

    <span style="color:orange">Draft</span>
  {% endif %}
  {%if doc.docstatus == 1 %}
    <span style="color:blue">Submitted</span>
  {% endif %}
  {%if doc.docstatus == 2 %}
    <span style="color:red">Cancelled</span>
  {% endif %}
  <p class="text-center">
      {{ doc.name }} <br>
      {{frappe.db.get_value("POS Profile", doc.pos_profile, "write_off_cost_center")}}    
  </p>

</div>

<!-- META -->
<div class="row">
  <div class="col">
    <div class="card">
      <div class="card-header">Información</div>
      <div class="card-body">
        <div><b>Cajera:</b> {{ cashier_name }}</div>
        <div><b>Perfil POS:</b> {{ doc.pos_profile }}</div>
        <div><b>Apertura:</b> {{ doc.pos_opening_shift }}</div>
      </div>
    </div>
  </div>

  <div class="col">
    <div class="card">
      <div class="card-header">Periodo</div>
      <div class="card-body">
        <div><b>Fecha:</b> {{ doc.posting_date }}</div>
        <div><b>Desde:</b> {{ doc.period_start_date | string | truncate(16, True, '') }}</div>
        <div><b>Hasta:</b> {{ doc.period_end_date | string | truncate(16, True, '') }}</div>
      </div>
    </div>
  </div>
</div>

<!-- FORMULA -->
<div class="card">
  <div class="card-header">Fórmula de Conciliación</div>
  <div class="card-body">

    <table>

      <tr>
        <td>Saldo de Apertura</td>
        <td class="sign"></td>
        <td class="amount pos">{{ fmt(ns.opening_bal) }}</td>
      </tr>

      <tr>
        <td>Entradas a Caja (Safe)</td>
        <td class="sign">+</td>
        <td class="amount pos">{{ fmt(ns.safe_total) }}</td>
      </tr>

      <tr>
        <td>Pagos Recibidos en Caja</td>
        <td class="sign">+</td>
        <td class="amount pos">{{ fmt(ns.cash_payment_total) }}</td>
      </tr>

      <tr>
        <td>Salidas / Cheques</td>
        <td class="sign">+</td>
        <td class="amount neg">{{ fmt(ns.check_total) }}</td>
      </tr>

      <tr>
        <td>Otros Movimientos (JV)</td>
        <td class="sign">+</td>
        <td class="amount {{ 'pos' if ns.other_total >= 0 else 'neg' }}">
          {{ fmt(ns.other_total) }}
        </td>
      </tr>

      <!-- SUPPLIERS -->
      {% for supplier, amt in inv_ns.suppliers.items() %}
      <tr>
        <td>{{ supplier }} ({{ inv_ns.qtys[supplier] }})</td>
        <td class="sign">+</td>
        <td class="amount pos">{{ fmt(amt) }}</td>
      </tr>
      {% endfor %}

      <tr class="total">
        <td>TOTAL ESPERADO</td>
        <td class="sign">=</td>
        <td class="amount">{{ fmt(expected) }}</td>
      </tr>

      <tr class="subtotal">
        <td>Saldo de Cierre</td>
        <td class="sign">−</td>
        <td class="amount">{{ fmt(closing_bal) }}</td>
      </tr>

      <tr class="diff">
        <td>DIFERENCIA</td>
        <td class="sign">=</td>
        <td class="amount {{ 'pos' if diff_val|round == 0 else 'neg' }}">
          {{ fmt(diff_val) }} {% if diff_val | round == 0 %}✔{% else %}✘{% endif %}
        </td>
      </tr>

    </table>

  </div>
</div>

<!-- PAYMENTS TABLE -->
<div class="card" style="margin-top:12px;">
  <div class="card-header">Modos de Pago</div>
  <div class="card-body">

    <table>

      <tr>
        <td class="text-center bold">Mode of Payment</td>
        <td class="text-right bold">Opening Amount</td>
        <td class="text-right bold">Closing Amount</td>
        <td class="text-right bold">Expected Amount</td>
        <td class="text-right bold">Difference</td>
      </tr>

      {% for p in doc.payment_reconciliation %}
        <tr>
          <td class="text-center">{{ p.mode_of_payment }}</td>
          <td class="amount">{{ fmt(p.opening_amount) }}</td>
          <td class="amount">{{ fmt(p.closing_amount) }}</td>
          <td class="amount">{{ fmt(p.expected_amount) }}</td>
          <td class="amount {{ 'pos' if p.difference == 0 else 'neg' }}">
            {{ fmt(p.difference) }} {% if p.difference == 0 %}✔{% else %}✘{% endif %}
          </td>
        </tr>
      {% endfor %}

    </table>

  </div>
</div>

<!-- SUMMARY -->
<div class="card" style="margin-top:12px;">
  <div class="card-header">Resumen del Turno</div>
  <div class="card-body">

    <table>

      <tr>
        <td>Total Transacciones</td>
        <td class="amount">{{ doc.total_quantity }}</td>
      </tr>

      <tr>
        <td>Grand Total</td>
        <td class="amount pos">{{ fmt(doc.grand_total) }}</td>
      </tr>

      <tr>
        <td>Net Total</td>
        <td class="amount">{{ fmt(doc.net_total) }}</td>
      </tr>

      {% for tax in doc.taxes %}
      <tr>
        <td>{{ tax.account_head }} ({{ tax.rate }}%)</td>
        <td class="amount">{{ fmt(tax.amount) }}</td>
      </tr>
      {% endfor %}

    </table>

  </div>
</div>

<!-- FOOTER -->
<div class="footer">
  {{ doc.company }} · {{ frappe.utils.now() | string | truncate(16, True, '') }}
</div>

</div>
